#include <stdio.h>
#define MAX 101
char stack[MAX];
int top = -1;
void push(char c) { if (top < MAX - 1) stack[++top] = c; }
char pop() { if (top >= 0) return stack[top--]; return '\0'; }
int main() {
    int T;
    scanf("%d", &T);
    getchar();
    for (int tc = 0; tc < T; ++tc) {
        char line[MAX];
        fgets(line, MAX, stdin);
        line[strcspn(line, "\n")] = '\0';
        top = -1;
        for (int i = 0; line[i]; ++i) push(line[i]);
        while (top >= 0) putchar(pop());
        if (tc < T - 1) putchar('\n');
    }
    return 0;
}

