#include <iostream>
using namespace std;
const int MAX = 101;
char myStack[MAX];
int top;
void push(char c) { if (top < MAX - 1) myStack[++top] = c; }
char pop() { if (top >= 0) return myStack[top--]; return '\0'; }
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    string dummy;
    getline(cin, dummy);
    for (int tc = 0; tc < T; ++tc) {
        string s;
        getline(cin, s);
        top = -1;
        for (char c : s) push(c);
        while (top >= 0) cout << pop();
        if (tc < T - 1) cout << '\n';
    }
    return 0;
}

